#!/usr/bin/env python3
"""Verify that the renaming changes are correct."""

import ast
import sys

def check_file(filepath, expected_changes):
    """Check that a file has the expected changes."""
    with open(filepath, 'r') as f:
        content = f.read()

    # Verify it's valid Python
    try:
        ast.parse(content)
        print(f"✓ {filepath} - valid Python syntax")
    except SyntaxError as e:
        print(f"✗ {filepath} - syntax error: {e}")
        return False

    # Check for expected changes
    for search_str, should_exist in expected_changes:
        if should_exist:
            if search_str in content:
                print(f"  ✓ Found: {search_str[:50]}")
            else:
                print(f"  ✗ Missing: {search_str[:50]}")
                return False
        else:
            if search_str not in content:
                print(f"  ✓ Removed: {search_str[:50]}")
            else:
                print(f"  ✗ Still present: {search_str[:50]}")
                return False

    return True

def main():
    """Run all verification checks."""
    print("Verifying _get_tags -> _estimator_tags renaming...\n")

    checks = {
        '/workspace/sklearn/base.py': [
            ('def _estimator_tags(self):', True),
            ('# Backward compatibility alias\n    _get_tags = _estimator_tags', True),
            ('The `_estimator_tags` method is deprecated', True),
        ],
        '/workspace/sklearn/utils/_tags.py': [
            ('- "_estimator_tags": to use the old tags infrastructure', True),
            ('if "_estimator_tags" in vars(klass):', True),
            ('return "_estimator_tags"', True),
            ('provider in ("_estimator_tags", "_more_tags")', True),
            ('tag_provider = "_estimator_tags"', True),
            ('if warn and tag_provider == "_estimator_tags":', True),
            ('use `_estimator_tags` and `_more_tags`', True),
        ],
        '/workspace/sklearn/utils/estimator_checks.py': [
            ('("_more_tags" in vars(klass) or "_estimator_tags" in vars(klass))', True),
            ('has defined either `_more_tags` or `_estimator_tags`,', True),
            ('`__sklearn_tags__` and `_more_tags` or `_estimator_tags`', True),
        ],
        '/workspace/sklearn/utils/tests/test_tags.py': [
            ('def test__estimator_tags_backward_compatibility():', True),
            ('The `_estimator_tags` method is deprecated in 1.6', True),
            ('predictor_cls()._estimator_tags()', True),
            ('has defined either `_more_tags` or `_estimator_tags`', True),
            ('Test that the `_more_tags` and `_estimator_tags` methods', True),
            ('BaseEstimator._estimator_tags(estimator)', True),
        ],
        '/workspace/sklearn/utils/tests/test_estimator_checks.py': [
            ('def _estimator_tags(self):', True),
            ('has defined either `_more_tags` or `_estimator_tags`', True),
        ],
    }

    all_ok = True
    for filepath, changes in checks.items():
        if not check_file(filepath, changes):
            all_ok = False
        print()

    if all_ok:
        print("✅ All verification checks passed!")
        return 0
    else:
        print("❌ Some verification checks failed!")
        return 1

if __name__ == "__main__":
    sys.exit(main())

